CREATE OR REPLACE VIEW vr_unkeep_loan (receive_year, receive_month, membership_no, loan_contract_no, begining_of_contract, loan_approve_amount, period_payment_amount, receipt_date, interest_arrear) AS SELECT sc_kep_t_monthly_receive.receive_year
, sc_kep_t_monthly_receive.receive_month
, sc_kep_t_monthly_receive.membership_no
, sc_lon_m_contract.loan_contract_no  
, sc_lon_m_contract.begining_of_contract 
, sc_lon_m_contract.loan_approve_amount
, sc_lon_m_contract.period_payment_amount 
, sc_kep_t_monthly_receive.receipt_date
--, sc_lon_m_loan_card.interest_arrear + PKA_LON_INTSRV.fp_calint(  sc_lon_m_contract.loan_contract_no   , to_date(  '!cal_date_1!' , 'dd/mm/yyyy'  ) )  as int_arr  
--, to_date(  '!cal_date_1!' , 'dd/mm/yyyy'  )  as cal_date
, sc_lon_m_loan_card.interest_arrear
FROM sc_kep_t_monthly_receive  
, sc_lon_m_contract
, sc_kep_t_monthly_receive_det  
, sc_lon_m_loan_card
WHERE 1=1
and sc_kep_t_monthly_receive_det.membership_no = sc_kep_t_monthly_receive.membership_no   
and sc_kep_t_monthly_receive_det.receive_year = sc_kep_t_monthly_receive.receive_year   
and sc_kep_t_monthly_receive_det.receive_month = sc_kep_t_monthly_receive.receive_month   
and sc_kep_t_monthly_receive_det.seq_no = sc_kep_t_monthly_receive.seq_no   
and sc_lon_m_contract.loan_contract_no = sc_kep_t_monthly_receive_det.receive_description  
and sc_lon_m_contract.loan_contract_no = sc_lon_m_loan_card.loan_contract_no  
and sc_kep_t_monthly_receive_det.keeping_type_code like 'ML%'  
and sc_kep_t_monthly_receive_det.unkeep_money_amount > 0     
and sc_lon_m_loan_card.principal_balance > 0   
and sc_kep_t_monthly_receive.ppm_status = '0'
/*WHERE*/

--and sc_kep_t_monthly_receive.receive_year = 2024   
--and sc_kep_t_monthly_receive.receive_month = 6   
ORDER BY sc_kep_t_monthly_receive.membership_no ASC
, sc_lon_m_contract.loan_contract_no ASC;

